  Future<ApiResponse<Map<String, dynamic>>> _executeRequest(
    Future<ApiResponse<Map<String, dynamic>>> Function() request,
    String url,
  ) async {
    try {
      final response = await request();
      _validateResponse(response, url);
      return response;
    } on TimeoutException {
      throw HttpServiceException(
        message: 'Request timed out',
        url: url,
      );
    } on SocketException catch (e) {
      throw HttpServiceException(
        message: 'Network error: Unable to connect. ${e.message}',
        url: url,
        originalError: e,
      );
    } on HandshakeException catch (e) {
      throw HttpServiceException(
        message: 'SSL/TLS handshake failed. ${e.message}',
        url: url,
        originalError: e,
      );
    } on HttpServiceException {
      rethrow;
    } catch (e) {
      throw HttpServiceException(
        message: 'Unexpected error: ${e.toString()}',
        url: url,
        originalError: e,
      );
    }
  }

  Future<ApiResponse<Map<String, dynamic>>> _executeWithRetry(
    Future<ApiResponse<Map<String, dynamic>>> Function() request,
    String url,
  ) async {
    int attempt = 0;
    while (true) {
      try {
        return await _executeRequest(request, url);
      } on HttpServiceException catch (e) {
        attempt++;
        final isRetryable = _isRetryableError(e);

        if (!isRetryable || attempt >= config.maxRetries) {
          rethrow;
        }

        // Exponential backoff
        final delay = config.retryDelay * (1 << (attempt - 1));
        await Future.delayed(delay);
      }
    }
  }

  bool _isRetryableError(HttpServiceException error) {
    if (error.statusCode != null) {
      return error.statusCode! >= 500 || error.statusCode == 429;
    }
    // Retry on network/timeout errors
    return error.originalError is SocketException ||
        error.originalError is TimeoutException ||
        error.message.contains('timed out') ||
        error.message.contains('Network error');
  }

  void _validateResponse(ApiResponse response, String url) {
    if (!response.isSuccess) {
      String message;
      switch (response.statusCode) {
        case 400:
          message = 'Bad request';
          break;
        case 401:
          message = 'Unauthorized - check authentication';
          break;
        case 403:
          message = 'Forbidden - insufficient permissions';
          break;
        case 404:
          message = 'Resource not found';
          break;
        case 408:
          message = 'Request timeout';
          break;
        case 429:
          message = 'Too many requests - rate limited';
          break;
        case 500:
          message = 'Internal server error';
          break;
        case 502:
          message = 'Bad gateway';
          break;
        case 503:
          message = 'Service unavailable';
          break;
        default:
          message = 'Request failed with status ${response.statusCode}';
      }
      throw HttpServiceException(
        message: message,
        statusCode: response.statusCode,
        url: url,
      );
    }
  }

  Future<bool> _checkDevice(
