// ---------------------------------------------------------------------------
// Singleton accessor for convenience
// ---------------------------------------------------------------------------

class HttpServiceProvider {
  static HttpService? _instance;

  static HttpService get instance {
    _instance ??= HttpService();
    return _instance!;
  }

  static void initialize({HttpServiceConfig? config, http.Client? client}) {
    _instance?.dispose();
    _instance = HttpService(config: config, client: client);
  }

  static void dispose() {
    _instance?.dispose();
    _instance = null;
  }
}

// ---------------------------------------------------------------------------
// Example usage
// ---------------------------------------------------------------------------

Future<void> main() async {
  // Initialize with custom config
  HttpServiceProvider.initialize(
    config: const HttpServiceConfig(
      cloudBaseUrl: 'https://api.example.com',
      cloudTimeout: Duration(seconds: 30),
      localDeviceTimeout: Duration(seconds: 5),
      maxRetries: 3,
    ),
  );

  final httpService = HttpServiceProvider.instance;

  // Set auth token for cloud requests
  httpService.setAuthToken('your-jwt-token-here');

  // --- Cloud API Examples ---
  try {
    // GET request to cloud
    final users = await httpService.cloudGet('/api/v1/users', queryParameters: {
      'page': '1',
      'limit': '20',
    });
    print('Cloud GET: ${users.data}');

    // POST request to cloud
    final newDevice = await httpService.cloudPost('/api/v1/devices', body: {
      'name': 'Living Room Sensor',
      'type': 'temperature',
      'ip': '192.168.1.100',
    });
    print('Cloud POST: ${newDevice.data}');

    // PUT request to cloud
    final updatedDevice =
        await httpService.cloudPut('/api/v1/devices/123', body: {
      'name': 'Updated Sensor Name',
    });
    print('Cloud PUT: ${updatedDevice.data}');

    // PATCH request to cloud
    final patchedDevice =
        await httpService.cloudPatch('/api/v1/devices/123', body: {
      'status': 'active',
    });
    print('Cloud PATCH: ${patchedDevice.data}');

    // DELETE request to cloud
    final deleteResult = await httpService.cloudDelete('/api/v1/devices/123');
    print('Cloud DELETE: ${deleteResult.statusCode}');
  } on HttpServiceException catch (e) {
    print('Cloud API Error: $e');
  }

  // --- Local IoT Device Examples ---
  try {
    // Check if device is reachable
    final isReachable = await httpService.isDeviceReachable(
      '192.168.1.100',
      port: 80,
      healthEndpoint: '/status',
    );
    print('Device reachable: $isReachable');

    if (isReachable) {
      // GET device status (HTTP - no TLS on basic IoT devices)
      final status = await httpService.deviceGet(
        '192.168.1.100',
        '/status',
        port: 80,
      );
      print('Device Status: ${status.data}');

      // POST command to device
      final commandResult = await httpService.devicePost(
        '192.168.1.100',
        '/api/command',
        port: 80,
        body: {
          'action': 'set_temperature',
          'value': 22.5,
        },
      );
      print('Device Command Result: ${commandResult.data}');

      // PUT configuration to device
      final configResult = await httpService.devicePut(
        '192.168.1.100',
        '/api/config',
        port: 80,
        body: {
          'reportInterval': 60,
          'units': 'celsius',
        },
      );
      print('Device Config Result: ${configResult.data}');
    }

    // Connect to a device that supports HTTPS
    final secureStatus = await httpService.deviceGet(
      '192.168.1.200',
      '/status',
      port: 443,
      useHttps: true,
    );
    print('Secure Device Status: ${secureStatus.data}');
  } on HttpServiceException catch (e) {
    print('Device Error: $e');
  }

  // --- Device Discovery ---
  try {
    final devices = await httpService.discoverDevices(
      '192.168.1',
      port: 80,
      healthEndpoint: '/status',
      scanTimeout: const Duration(seconds: 2),
    );
    print('Discovered devices: $devices');
  } catch (e) {
    print('Discovery error: $e');
  }

  // Cleanup
  HttpServiceProvider.dispose();
}